classdef PaperStudySyntheticCase
    %PAPERSTUDYSYNTHETICCASE Render one frozen P2 case and exact truth.
    %
    % Imagery uses the unbiased camera pair. Matching geometry may use the
    % case's declared biased moving pinhole camera. All uint16 radiometry is
    % quantized back to the manifest's ten true bits before matching arrays
    % are scaled to [0,1]. Traceability: algo/main.tex Secs. 10.2--10.3 and
    % the unified experimental program; paper_study_v1 execution parameters.

    properties (SetAccess = private)
        Case (1, 1) struct
        SceneContract (1, 1) struct
        ExecutionParameters (1, 1) struct
        Renderer
        MatchingMovingCamera
    end

    methods
        function obj = PaperStudySyntheticCase(caseRow, manifest)
            arguments
                caseRow table {mustBePaperStudyCaseRow}
                manifest (1, 1) struct {mustBePaperStudyCaseManifest}
            end

            c = table2struct(caseRow);
            obj.Case = c;
            obj.SceneContract = manifest.sceneContract;
            obj.ExecutionParameters = manifest.executionParameters;
            obj.Renderer = PaperStudySyntheticCase.createRenderer( ...
                c, manifest.sceneContract, manifest.executionParameters);
            obj.MatchingMovingCamera = ...
                PaperStudySyntheticCase.biasedCamera( ...
                obj.Renderer.MovingCamera, c);
        end

        function result = render(obj, options)
            %RENDER Produce common images, labels, samples, and truth arrays.
            arguments
                obj (1, 1) PaperStudySyntheticCase
                options.WorkingPrecision (1, 1) string ...
                    {mustBeMember(options.WorkingPrecision, ...
                    ["single", "double"])} = "single"
                options.DeltaHeightMetres (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 0.5
                options.DeltaPixel (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 0.25
            end

            timer = tic;
            pair = obj.Renderer.renderPair;
            moving = PaperStudySyntheticCase.applyRadiometry( ...
                pair.MovingImage, obj.Renderer.BitDepth, ...
                obj.Case, obj.ExecutionParameters.radiometry);
            levels = 2 ^ obj.Renderer.BitDepth - 1;
            referenceMatch = cast( ...
                double(pair.ReferenceImage) ./ levels, ...
                options.WorkingPrecision);
            movingMatch = cast(double(moving) ./ levels, ...
                options.WorkingPrecision);
            denseTruth = obj.denseTruth(pair.ReferenceValid);
            p = PaperStudySyntheticCase.samplePoints( ...
                obj.Renderer.ImageSize, ...
                obj.SceneContract.samplePointLimitPerScene);
            [world, referenceTruthValid, kind] = ...
                obj.Renderer.surfaceIntersection( ...
                obj.Renderer.ReferenceCamera, p);
            [truthCorrespondence, movingTruthValid] = ...
                obj.Renderer.MovingCamera.worldToImage(world);
            projectedTruthCorrespondence = truthCorrespondence;
            movingTruthInside = obj.Renderer.MovingCamera.isInsideImage( ...
                truthCorrespondence, 1);
            [movingSurfaceWorld, movingSurfaceValid] = ...
                obj.Renderer.surfaceIntersection( ...
                obj.Renderer.MovingCamera, truthCorrespondence);
            movingClosureError = vecnorm( ...
                movingSurfaceWorld - world, 2, 2);
            % Exact visibility for Sec. 10 common evidence: projection into
            % pi2 is necessary but not sufficient; its nearest surface hit
            % must close on pi1^{-1}(p,z) in world coordinates.
            movingVisible = movingTruthValid & movingTruthInside ...
                & movingSurfaceValid & movingClosureError <= ...
                obj.SceneContract.visibilityWorldToleranceMetres;
            movingOccluded = referenceTruthValid & movingTruthValid ...
                & movingTruthInside & movingSurfaceValid ...
                & movingClosureError > ...
                obj.SceneContract.visibilityWorldToleranceMetres;
            referenceMaskValid = PaperStudySyntheticCase.maskAtPoints( ...
                pair.ReferenceValid, p);
            truthValid = referenceTruthValid & movingVisible ...
                & referenceMaskValid;
            truthHeight = world(:, 3);
            truthHeight(~truthValid) = NaN;
            truthCorrespondence(~truthValid, :) = NaN;

            modelGeometry = HeightSweepGeometry( ...
                obj.Renderer.ReferenceCamera, obj.MatchingMovingCamera);
            zmid = mean(double(obj.SceneContract.heightRangeMetres));
            [~, kappa, derivativeValid] = modelGeometry.heightDerivative( ...
                p, zmid, DeltaHeight=options.DeltaHeightMetres);
            goodKappa = derivativeValid & isfinite(kappa) & kappa > 0;
            if ~any(goodKappa)
                error("PaperStudySyntheticCase:NoValidObservability", ...
                    "Case %s has no valid sampled height derivative.", ...
                    string(obj.Case.Identifier));
            end
            medianKappa = median(kappa(goodKappa));
            range = double(obj.SceneContract.heightRangeMetres);
            target = obj.SceneContract.targetProjectedMotionPixels;
            labelCount = max(3, ceil(diff(range) .* medianKappa ...
                ./ target) + 1);
            labels = linspace(range(1), range(2), labelCount);
            actualMotion = diff(range) ./ (labelCount - 1) .* medianKappa;

            trueGeometry = HeightSweepGeometry( ...
                obj.Renderer.ReferenceCamera, ...
                obj.Renderer.MovingCamera);
            [heightDirection, truthKappa, heightDerivativeValid] = ...
                trueGeometry.heightDerivative( ...
                p, truthHeight, DeltaHeight=options.DeltaHeightMetres);
            [planeJacobian, planeJacobianValid] = ...
                trueGeometry.warpJacobian( ...
                p, truthHeight, DeltaPixel=options.DeltaPixel);
            [slope, slopeValid] = obj.surfaceSlope( ...
                p, kind, options.DeltaPixel);
            surfaceJacobian = HeightSweepGeometry.surfaceJacobian( ...
                planeJacobian, heightDirection, slope);
            jacobianValid = truthValid & heightDerivativeValid ...
                & planeJacobianValid & slopeValid;
            surfaceJacobian(~jacobianValid, :, :) = NaN;

            result = struct( ...
                "Identifier", string(obj.Case.Identifier), ...
                "Suite", string(obj.Case.Suite), ...
                "Factors", obj.Case, ...
                "ReferenceImageUint16", pair.ReferenceImage, ...
                "MovingImageUint16", moving, ...
                "ReferenceImage", referenceMatch, ...
                "MovingImage", movingMatch, ...
                "ReferenceValid", pair.ReferenceValid, ...
                "MovingValid", pair.MovingValid, ...
                "DenseTruth", denseTruth, ...
                "ReferenceCamera", obj.Renderer.ReferenceCamera, ...
                "TrueMovingCamera", obj.Renderer.MovingCamera, ...
                "MatchingMovingCamera", obj.MatchingMovingCamera, ...
                "SamplePixelXY", p, ...
                "TruthWorldENU", world, ...
                "TruthHeightMetres", truthHeight, ...
                "TruthCorrespondenceXY", truthCorrespondence, ...
                "ProjectedTruthCorrespondenceXY", ...
                projectedTruthCorrespondence, ...
                "ReferenceTruthSurfaceValid", referenceTruthValid, ...
                "MovingTruthProjectionValid", movingTruthValid, ...
                "MovingTruthInside", movingTruthInside, ...
                "MovingTruthVisible", movingVisible, ...
                "MovingTruthOccluded", movingOccluded, ...
                "MovingTruthSurfaceValid", movingSurfaceValid, ...
                "MovingTruthClosureErrorMetres", movingClosureError, ...
                "TruthSurfaceKind", kind, ...
                "TruthValid", truthValid, ...
                "TruthHeightDirectionXY", heightDirection, ...
                "TruthObservabilityPixelsPerMetre", truthKappa, ...
                "TruthSurfaceSlopeMetresPerPixel", slope, ...
                "TruthWarpJacobian", surfaceJacobian, ...
                "TruthJacobianValid", jacobianValid, ...
                "HeightLabelsMetres", labels, ...
                "MedianModelObservabilityPixelsPerMetre", medianKappa, ...
                "ActualMedianProjectedMotionPixels", actualMotion, ...
                "Radiometry", string(obj.Case.Radiometry), ...
                "CameraBias", string(obj.Case.CameraBias), ...
                "WorkingPrecision", options.WorkingPrecision, ...
                "PixelConvention", ...
                "one-based [x,y]=[column,row] pixel centers", ...
                "WorldFrame", obj.Renderer.ReferenceCamera.WorldFrame, ...
                "ElevationDatum", ...
                obj.Renderer.ReferenceCamera.ElevationDatum, ...
                "RenderSeconds", toc(timer));
        end
    end

    methods (Access = private)
        function truth = denseTruth(obj, referenceMask)
            %DENSETRUTH Exact nearest-surface truth on every reference center.
            % Traceability: Sec. 10 common evidence and exact
            % w(p,z)=pi2(pi1_inverse(p,z)) visibility contract.
            imageSize = obj.Renderer.ImageSize;
            [y, x] = ndgrid(1:imageSize(1), 1:imageSize(2));
            p = [x(:), y(:)];
            [world, referenceSurfaceValid, kind] = ...
                obj.Renderer.surfaceIntersection( ...
                obj.Renderer.ReferenceCamera, p);
            [projected, movingProjectionValid] = ...
                obj.Renderer.MovingCamera.worldToImage(world);
            movingInside = obj.Renderer.MovingCamera.isInsideImage( ...
                projected, 1);
            [movingWorld, movingSurfaceValid] = ...
                obj.Renderer.surfaceIntersection( ...
                obj.Renderer.MovingCamera, projected);
            closure = vecnorm(movingWorld - world, 2, 2);
            tolerance = obj.SceneContract.visibilityWorldToleranceMetres;
            movingVisible = movingProjectionValid & movingInside ...
                & movingSurfaceValid & closure <= tolerance;
            movingOccluded = referenceSurfaceValid ...
                & movingProjectionValid & movingInside ...
                & movingSurfaceValid & closure > tolerance;
            referenceMaskValid = PaperStudySyntheticCase.maskAtPoints( ...
                referenceMask, p);
            valid = referenceSurfaceValid & movingVisible ...
                & referenceMaskValid;
            correspondence = projected;
            correspondence(~valid, :) = NaN;
            height = world(:, 3);
            height(~valid) = NaN;
            truth = struct( ...
                "WorldENU", reshape(world, [imageSize, 3]), ...
                "HeightMetres", reshape(height, imageSize), ...
                "CorrespondenceXY", reshape( ...
                correspondence, [imageSize, 2]), ...
                "ProjectedCorrespondenceXY", reshape( ...
                projected, [imageSize, 2]), ...
                "ReferenceSurfaceValid", reshape( ...
                referenceSurfaceValid, imageSize), ...
                "ReferenceMaskValid", reshape( ...
                referenceMaskValid, imageSize), ...
                "MovingProjectionValid", reshape( ...
                movingProjectionValid, imageSize), ...
                "MovingInside", reshape(movingInside, imageSize), ...
                "MovingSurfaceValid", reshape( ...
                movingSurfaceValid, imageSize), ...
                "MovingVisible", reshape(movingVisible, imageSize), ...
                "MovingOccluded", reshape(movingOccluded, imageSize), ...
                "MovingClosureErrorMetres", reshape(closure, imageSize), ...
                "SurfaceKind", reshape(kind, imageSize), ...
                "Valid", reshape(valid, imageSize), ...
                "VisibilityWorldToleranceMetres", tolerance, ...
                "Definition", ...
                "nearest moving-surface hit closes on projected truth world point");
        end

        function [slope, valid] = surfaceSlope(obj, p, kind, delta)
            [xp, vp, kp] = obj.Renderer.surfaceIntersection( ...
                obj.Renderer.ReferenceCamera, p + [delta, 0]);
            [xm, vm, km] = obj.Renderer.surfaceIntersection( ...
                obj.Renderer.ReferenceCamera, p - [delta, 0]);
            [yp, vpy, kyp] = obj.Renderer.surfaceIntersection( ...
                obj.Renderer.ReferenceCamera, p + [0, delta]);
            [ym, vmy, kym] = obj.Renderer.surfaceIntersection( ...
                obj.Renderer.ReferenceCamera, p - [0, delta]);
            valid = vp & vm & vpy & vmy ...
                & kp == kind & km == kind & kyp == kind & kym == kind;
            slope = [(xp(:, 3) - xm(:, 3)) ./ (2 .* delta), ...
                (yp(:, 3) - ym(:, 3)) ./ (2 .* delta)];
            if obj.Renderer.SurfaceType == "step"
                valid = valid & abs(xp(:, 3) - xm(:, 3)) ...
                    < obj.Renderer.StepHeightMetres ./ 2 ...
                    & abs(yp(:, 3) - ym(:, 3)) ...
                    < obj.Renderer.StepHeightMetres ./ 2;
            end
            valid = valid & all(isfinite(slope), 2);
            slope(~valid, :) = NaN;
        end
    end

    methods (Static, Access = private)
        function renderer = createRenderer(c, scene, execution)
            surface = string(c.Surface);
            surfaceType = "plane";
            along = 0;
            cross = 0;
            stepHeight = 0;
            sincAmplitude = execution.surface.sincAmplitudeMetres;
            terrainCurvature = 0;
            buildings = zeros(0, 5);
            switch surface
                case "along-slope"
                    along = execution.surface.planeSlopeDegrees;
                case "cross-slope"
                    cross = execution.surface.planeSlopeDegrees;
                case "step"
                    surfaceType = "step";
                    stepHeight = execution.surface.stepHeightMetres;
                case "sinc"
                    surfaceType = "radial-sinc";
                case "hillside-buildings"
                    surfaceType = "hillside-buildings";
                    along = execution.surface.hillsideAlongSlopeDegrees;
                    cross = execution.surface.hillsideCrossSlopeDegrees;
                    terrainCurvature = execution.surface. ...
                        hillsideTerrainCurvaturePerMetre;
                    buildings = execution.surface.hillsideBuildings;
            end
            texture = string(c.Texture);
            if texture == "repeated-roof"
                texture = "repeated";
            end
            renderer = SyntheticPinholeRenderer( ...
                string(c.Identifier), double(scene.imageSize), ...
                Suite=string(c.Suite), BitDepth=scene.bitDepth, ...
                MeanObliquityDegrees=c.ObliquityDegrees, ...
                ConvergenceDegrees=c.ConvergenceDegrees, ...
                LookAzimuthDegrees=execution.lookAzimuthDegrees, ...
                AlongTrackSlopeDegrees=along, ...
                CrossTrackSlopeDegrees=cross, ...
                SurfaceType=surfaceType, StepHeightMetres=stepHeight, ...
                StepDirection=string(execution.surface.stepDirection), ...
                SincAmplitudeMetres=sincAmplitude, ...
                SincLobeSpacingMetres= ...
                execution.surface.sincLobeSpacingMetres, ...
                TerrainCurvaturePerMetre=terrainCurvature, ...
                Buildings=buildings, ...
                SearchRangeMetres=double(scene.heightRangeMetres), ...
                TargetMotionPerLabelPixels= ...
                scene.targetProjectedMotionPixels, ...
                Supersample=execution.supersample, ...
                PsfSigmaPixels=execution.psfSigmaPixels, ...
                TextureSeed=c.Seed, TextureType=texture);
        end

        function camera = biasedCamera(trueCamera, c)
            k = trueCamera.K;
            switch string(c.CameraBias)
                case "constant"
                    k(1, 3) = k(1, 3) + c.SampleBiasPixels;
                    k(2, 3) = k(2, 3) + c.LineBiasPixels;
                case "linear-drift"
                    cx = (trueCamera.ImageSize(2) + 1) ./ 2;
                    cy = (trueCamera.ImageSize(1) + 1) ./ 2;
                    hx = max((trueCamera.ImageSize(2) - 1) ./ 2, 1);
                    hy = max((trueCamera.ImageSize(1) - 1) ./ 2, 1);
                    h = eye(3);
                    h(1, 2) = c.SampleDriftPixels ./ hy;
                    h(1, 3) = -h(1, 2) .* cy;
                    h(2, 1) = c.LineDriftPixels ./ hx;
                    h(2, 3) = -h(2, 1) .* cx;
                    k = h * k;
            end
            camera = PinholeCamera( ...
                k, trueCamera.R, trueCamera.C, trueCamera.ImageSize);
        end

        function moving = applyRadiometry(image, bitDepth, c, options)
            kind = string(c.Radiometry);
            if kind == "polarity-reversal"
                kind = "polarity";
            end
            moving = SyntheticRadiometry.apply( ...
                image, bitDepth, kind, Gain=options.gain, ...
                Offset=options.offset, Gamma=options.gamma, ...
                BlurSigmaPixels=options.blurSigmaPixels, ...
                NoiseSigma=options.noiseSigma, Seed=c.Seed + 100000, ...
                ShadowAttenuation=options.shadowAttenuation, ...
                ShadowBoundaryFraction=options.shadowBoundaryFraction);
        end

        function p = samplePoints(imageSize, limit)
            side = ceil(sqrt(limit));
            margin = min(12, floor((min(imageSize) - 1) ./ 4));
            x = unique(round(linspace(1 + margin, ...
                imageSize(2) - margin, side)));
            y = unique(round(linspace(1 + margin, ...
                imageSize(1) - margin, side)));
            [yy, xx] = ndgrid(y, x);
            p = [xx(:), yy(:)];
            p = p(1:min(limit, size(p, 1)), :);
        end

        function valid = maskAtPoints(mask, p)
            index = sub2ind(size(mask), p(:, 2), p(:, 1));
            valid = mask(index);
        end
    end
end

function mustBePaperStudyCaseRow(row)
required = ["Suite", "Identifier", "Seed", "Surface", "Texture", ...
    "ConvergenceDegrees", "ObliquityDegrees", "Radiometry", ...
    "CameraBias", "LineBiasPixels", "SampleBiasPixels", ...
    "LineDriftPixels", "SampleDriftPixels"];
if height(row) ~= 1 || ~all(ismember( ...
        required, string(row.Properties.VariableNames)))
    error("PaperStudySyntheticCase:InvalidCaseRow", ...
        "A case must be one complete PaperStudyContract plan row.");
end
end

function mustBePaperStudyCaseManifest(s)
if ~all(isfield(s, ...
        ["sceneContract", "executionParameters"]))
    error("PaperStudySyntheticCase:InvalidManifest", ...
        "The manifest lacks scene or execution parameters.");
end
end
